pub type ApiKeyStore = Mutex<HashMap<String, String>>;

fn api_keys_path() -> PathBuf {
    let mut base = std::env::var("APPDATA")
        .ok()
        .map(PathBuf::from)
        .or_else(|| std::env::var("HOME").ok().map(|h| PathBuf::from(h).join(".config")))
        .unwrap_or_else(|| PathBuf::from("."));
    base = base.join("NovaSyn");
    base = base.join("api-keys.json");
    base
}

pub fn load_api_keys() -> HashMap<String, String> {
    let path = api_keys_path();
    if !path.exists() {
        return HashMap::new();
    }
    match std::fs::read_to_string(&path) {
        Ok(content) => serde_json::from_str(&content).unwrap_or_default(),
        Err(_) => HashMap::new(),
    }
}

pub fn save_api_keys(keys: &HashMap<String, String>) -> Result<(), String> {
    let path = api_keys_path();
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent).map_err(|e| e.to_string())?;
    }
    let content = serde_json::to_string_pretty(keys).map_err(|e| e.to_string())?;
    std::fs::write(&path, content).map_err(|e| e.to_string())
}

#[tauri::command]
pub fn get_api_keys(store: tauri::State<'_, ApiKeyStore>) -> Result<HashMap<String, String>, String> {
    let keys = store.lock().map_err(|e| e.to_string())?;
    // Return masked keys to renderer (don't expose raw keys)
    let masked: HashMap<String, String> = keys.iter()
        .map(|(k, v)| {
            let masked = if v.len() > 8 {
                format!("{}...{}", &v[..4], &v[v.len()-4..])
            } else {
                "***".to_string()
            };
            (k.clone(), masked)
        })
        .collect();
    Ok(masked)
}

#[tauri::command]
pub fn set_api_key(provider: String, key: String, store: tauri::State<'_, ApiKeyStore>) -> Result<(), String> {
    let mut keys = store.lock().map_err(|e| e.to_string())?;
    if key.is_empty() {
        keys.remove(&provider);
    } else {
        keys.insert(provider, key);
    }
    save_api_keys(&keys)
}

fn provider_from_model(model: &str) -> &'static str {
    if model.starts_with("claude") { return "anthropic"; }
    if model.starts_with("gpt-") || model.starts_with("o1") || model.starts_with("o3") || model.starts_with("o4") || model.starts_with("chatgpt-") { return "openai"; }
    "anthropic"
}

#[tauri::command]
pub async fn send_chat(
    request: ChatRequest,
    request_id: String,
    window: Window,
    store: tauri::State<'_, ApiKeyStore>,
) -> Result<ChatResponse, String> {
    let provider = provider_from_model(&request.model);
    let api_key = {
        let keys = store.lock().map_err(|e| e.to_string())?;
        keys.get(provider).cloned()
    };
    let api_key = api_key.ok_or_else(|| format!("No API key configured for {}", provider))?;

    match provider {
        "anthropic" => call_anthropic(request, request_id, window, api_key).await,
        "openai" => call_openai(request, request_id, window, api_key).await,
        _ => Err(format!("Unsupported provider: {}", provider)),
    }
}

async fn call_anthropic(
    request: ChatRequest,
    request_id: String,
    window: Window,
    api_key: String,
) -> Result<ChatResponse, String> {
    let client = reqwest::Client::new();

    // Anthropic separates the system prompt from the message list
    let messages: Vec<serde_json::Value> = request.messages.iter()
        .filter(|m| m.role != "system")
        .map(|m| serde_json::json!({"role": m.role, "content": m.content}))
        .collect();

    let max_tokens = request.max_tokens.unwrap_or(8192);
    let mut body = serde_json::json!({
        "model": request.model,
        "max_tokens": max_tokens,
        "temperature": request.temperature.unwrap_or(0.7),
        "messages": messages,
        "stream": true,
    });
    if let Some(sys) = &request.system_prompt {
        body["system"] = serde_json::json!(sys);
    }

    let response = client
        .post("https://api.anthropic.com/v1/messages")
        .header("x-api-key", &api_key)
        .header("anthropic-version", "2023-06-01")
        .header("content-type", "application/json")
        .json(&body)
        .send()
        .await
        .map_err(|e| e.to_string())?;

    if !response.status().is_success() {
        let err_text = response.text().await.unwrap_or_default();
        return Err(format!("Anthropic API error: {}", err_text));
    }

    let mut full_content = String::new();
    let mut input_tokens = 0u32;
    let mut output_tokens = 0u32;
    let mut bytes_stream = response.bytes_stream();
    use futures_util::StreamExt;

    let stream_result: Result<(), String> = async {
        while let Some(chunk) = bytes_stream.next().await {
            let chunk = chunk.map_err(|e| e.to_string())?;
            let text = String::from_utf8_lossy(&chunk);
            for line in text.lines() {
                if let Some(data) = line.strip_prefix("data: ") {
                    if data == "[DONE]" { continue; }
                    if let Ok(event) = serde_json::from_str::<serde_json::Value>(data) {
                        let event_type = event["type"].as_str().unwrap_or("");
                        if event_type == "content_block_delta" {
                            if let Some(delta_text) = event["delta"]["text"].as_str() {
                                full_content.push_str(delta_text);
                                let _ = window.emit("chat-stream", StreamDelta {
                                    request_id: request_id.clone(),
                                    delta: delta_text.to_string(),
                                    done: false,
                                });
                            }
                        } else if event_type == "message_start" {
                            if let Some(t) = event["message"]["usage"]["input_tokens"].as_u64() {
                                input_tokens = t as u32;
                            }
                        } else if event_type == "message_delta" {
                            if let Some(t) = event["usage"]["output_tokens"].as_u64() {
                                output_tokens = t as u32;
                            }
                        }
                    }
                }
            }
        }
        Ok(())
    }.await;

    // Partial-content recovery: if the stream died but we got something,
    // return what we have rather than failing the whole request.
    if let Err(err) = stream_result {
        if full_content.is_empty() {
            return Err(format!("Anthropic stream failed: {}", err));
        }
        eprintln!("[Anthropic] stream interrupted after {} chars: {}", full_content.len(), err);
    }

    let _ = window.emit("chat-stream", StreamDelta {
        request_id: request_id.clone(),
        delta: String::new(),
        done: true,
    });

    Ok(ChatResponse {
        content: full_content,
        model: request.model,
        provider: "anthropic".to_string(),
        input_tokens,
        output_tokens,
    })
}

// True for OpenAI reasoning models (o1/o3/o4) — they require
// max_completion_tokens (not max_tokens) and don't accept temperature.
fn is_openai_reasoning_model(model: &str) -> bool {
    model.starts_with("o1") || model.starts_with("o3") || model.starts_with("o4")
}

// True for GPT-5.x — uses max_completion_tokens but still accepts temperature.
fn is_openai_gpt5(model: &str) -> bool {
    model.starts_with("gpt-5")
}

async fn call_openai(
    request: ChatRequest,
    request_id: String,
    window: Window,
    api_key: String,
) -> Result<ChatResponse, String> {
    let client = reqwest::Client::new();

    let mut messages: Vec<serde_json::Value> = vec![];
    if let Some(sys) = &request.system_prompt {
        messages.push(serde_json::json!({"role": "system", "content": sys}));
    }
    for m in &request.messages {
        messages.push(serde_json::json!({"role": m.role, "content": m.content}));
    }

    let max_tokens = request.max_tokens.unwrap_or(8192);
    let mut body = serde_json::json!({
        "model": request.model,
        "messages": messages,
        "stream": true,
        "stream_options": {"include_usage": true},
    });

    // Reasoning vs chat-completion parameter switch
    if is_openai_reasoning_model(&request.model) {
        // Reasoning models: max_completion_tokens, no temperature
        body["max_completion_tokens"] = serde_json::json!(max_tokens);
    } else if is_openai_gpt5(&request.model) {
        // GPT-5.x: max_completion_tokens, temperature ok
        body["max_completion_tokens"] = serde_json::json!(max_tokens);
        body["temperature"] = serde_json::json!(request.temperature.unwrap_or(0.7));
    } else {
        body["max_tokens"] = serde_json::json!(max_tokens);
        body["temperature"] = serde_json::json!(request.temperature.unwrap_or(0.7));
    }

    let response = client
        .post("https://api.openai.com/v1/chat/completions")
        .header("Authorization", format!("Bearer {}", api_key))
        .header("Content-Type", "application/json")
        .json(&body)
        .send()
        .await
        .map_err(|e| e.to_string())?;

    if !response.status().is_success() {
        let err_text = response.text().await.unwrap_or_default();
        return Err(format!("OpenAI API error: {}", err_text));
    }

    let mut full_content = String::new();
    let mut input_tokens = 0u32;
    let mut output_tokens = 0u32;
    let mut bytes_stream = response.bytes_stream();
    use futures_util::StreamExt;

    let stream_result: Result<(), String> = async {
        while let Some(chunk) = bytes_stream.next().await {
            let chunk = chunk.map_err(|e| e.to_string())?;
            let text = String::from_utf8_lossy(&chunk);
            for line in text.lines() {
                if let Some(data) = line.strip_prefix("data: ") {
                    if data == "[DONE]" { continue; }
                    if let Ok(event) = serde_json::from_str::<serde_json::Value>(data) {
                        if let Some(delta_text) = event["choices"][0]["delta"]["content"].as_str() {
                            full_content.push_str(delta_text);
                            let _ = window.emit("chat-stream", StreamDelta {
                                request_id: request_id.clone(),
                                delta: delta_text.to_string(),
                                done: false,
                            });
                        }
                        if let Some(usage) = event["usage"].as_object() {
                            input_tokens = usage.get("prompt_tokens").and_then(|v| v.as_u64()).unwrap_or(0) as u32;
                            output_tokens = usage.get("completion_tokens").and_then(|v| v.as_u64()).unwrap_or(0) as u32;
                        }
                    }
                }
            }
        }
        Ok(())
    }.await;

    if let Err(err) = stream_result {
        if full_content.is_empty() {
            return Err(format!("OpenAI stream failed: {}", err));
        }
        eprintln!("[OpenAI] stream interrupted after {} chars: {}", full_content.len(), err);
    }

    let _ = window.emit("chat-stream", StreamDelta {
        request_id: request_id.clone(),
        delta: String::new(),
        done: true,
    });

    Ok(ChatResponse {
        content: full_content,
        model: request.model,
        provider: "openai".to_string(),
        input_tokens,
        output_tokens,
    })
}

