#[derive(Debug, Clone, Serialize, Deserialize)]
struct ProviderCache {
    last_fetched: String,
    models: Vec<ModelInfo>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct ModelCacheFile {
    version: u32,
    providers: HashMap<String, ProviderCache>,
}

const CACHE_VERSION: u32 = 1;
const CACHE_TTL_SECS: i64 = 24 * 60 * 60;

fn model_cache_path() -> PathBuf {
    let mut p = api_keys_path();
    p.pop();
    p.join("model-cache.json")
}

fn load_model_cache() -> ModelCacheFile {
    match std::fs::read_to_string(model_cache_path()) {
        Ok(content) => {
            match serde_json::from_str::<ModelCacheFile>(&content) {
                Ok(c) if c.version == CACHE_VERSION => c,
                _ => ModelCacheFile { version: CACHE_VERSION, providers: HashMap::new() },
            }
        }
        Err(_) => ModelCacheFile { version: CACHE_VERSION, providers: HashMap::new() },
    }
}

fn save_model_cache(cache: &ModelCacheFile) {
    let path = model_cache_path();
    if let Some(parent) = path.parent() {
        let _ = std::fs::create_dir_all(parent);
    }
    if let Ok(content) = serde_json::to_string_pretty(cache) {
        let _ = std::fs::write(&path, content);
    }
}

fn cache_is_fresh(cache: &ModelCacheFile, provider: &str) -> bool {
    let entry = match cache.providers.get(provider) {
        Some(e) => e,
        None => return false,
    };
    match chrono::DateTime::parse_from_rfc3339(&entry.last_fetched) {
        Ok(dt) => {
            let age = chrono::Utc::now().signed_duration_since(dt.with_timezone(&chrono::Utc));
            age.num_seconds() < CACHE_TTL_SECS
        }
        Err(_) => false,
    }
}

// Detect dated model variants like "...-2024-08-06" without pulling in a regex crate
fn has_date_suffix(id: &str) -> bool {
    let bytes = id.as_bytes();
    if bytes.len() < 11 { return false; }
    for i in 0..=(bytes.len() - 11) {
        if bytes[i] == b'-'
            && bytes[i+1].is_ascii_digit() && bytes[i+2].is_ascii_digit()
            && bytes[i+3].is_ascii_digit() && bytes[i+4].is_ascii_digit()
            && bytes[i+5] == b'-'
            && bytes[i+6].is_ascii_digit() && bytes[i+7].is_ascii_digit()
            && bytes[i+8] == b'-'
            && bytes[i+9].is_ascii_digit() && bytes[i+10].is_ascii_digit()
        {
            return true;
        }
    }
    false
}

async fn discover_anthropic_models(api_key: &str) -> Result<Vec<ModelInfo>, String> {
    let client = reqwest::Client::new();
    let mut all = Vec::new();
    let mut after_id: Option<String> = None;

    loop {
        let mut url = "https://api.anthropic.com/v1/models?limit=100".to_string();
        if let Some(ref aid) = after_id {
            url.push_str(&format!("&after_id={}", aid));
        }
        let resp = client.get(&url)
            .header("x-api-key", api_key)
            .header("anthropic-version", "2023-06-01")
            .send()
            .await
            .map_err(|e| e.to_string())?;
        if !resp.status().is_success() {
            return Err(format!("Anthropic models {}: {}", resp.status(), resp.text().await.unwrap_or_default()));
        }
        let data: serde_json::Value = resp.json().await.map_err(|e| e.to_string())?;
        if let Some(arr) = data["data"].as_array() {
            for m in arr {
                let id = m["id"].as_str().unwrap_or("").to_string();
                if id.is_empty() { continue; }
                all.push(ModelInfo {
                    name: m["display_name"].as_str().unwrap_or(&id).to_string(),
                    id: id.clone(),
                    provider: "anthropic".to_string(),
                    model_id: id,
                    context_window: m["max_input_tokens"].as_u64().unwrap_or(200000),
                    max_output_tokens: m["max_tokens"].as_u64().unwrap_or(8192),
                    capabilities: ModelCapabilities {
                        chat: true,
                        structured_output: m["capabilities"]["structured_outputs"]["supported"].as_bool().unwrap_or(false),
                        thinking: m["capabilities"]["thinking"]["supported"].as_bool().unwrap_or(false),
                        vision: m["capabilities"]["image_input"]["supported"].as_bool().unwrap_or(false),
                    },
                    created_at: m["created_at"].as_str().unwrap_or("").to_string(),
                });
            }
        }
        if data["has_more"].as_bool().unwrap_or(false) {
            after_id = data["last_id"].as_str().map(|s| s.to_string());
            if after_id.is_none() { break; }
        } else {
            break;
        }
    }

    Ok(all)
}

async fn discover_openai_models(api_key: &str) -> Result<Vec<ModelInfo>, String> {
    let client = reqwest::Client::new();
    let resp = client.get("https://api.openai.com/v1/models")
        .header("Authorization", format!("Bearer {}", api_key))
        .send()
        .await
        .map_err(|e| e.to_string())?;
    if !resp.status().is_success() {
        return Err(format!("OpenAI models {}: {}", resp.status(), resp.text().await.unwrap_or_default()));
    }
    let data: serde_json::Value = resp.json().await.map_err(|e| e.to_string())?;
    let mut out = Vec::new();
    let chat_prefixes = ["gpt-", "o1", "o3", "o4", "chatgpt-"];
    let skip = ["realtime", "audio", "search", "transcribe", "tts", "whisper", "embedding", "dall-e", "gpt-image", "moderation"];
    if let Some(arr) = data["data"].as_array() {
        for m in arr {
            let id = m["id"].as_str().unwrap_or("").to_lowercase();
            if id.is_empty() { continue; }
            if !chat_prefixes.iter().any(|p| id.starts_with(p)) { continue; }
            if skip.iter().any(|p| id.contains(p)) { continue; }
            if id.starts_with("ft:") { continue; }
            // Skip dated versions (e.g., gpt-4o-2024-08-06): scan for "-YYYY-MM-DD"
            if has_date_suffix(&id) { continue; }
            let context = match id.as_str() {
                s if s.starts_with("gpt-5") => 400000,
                s if s.starts_with("gpt-4.1") => 1047576,
                s if s.starts_with("o3") || s.starts_with("o4") => 200000,
                s if s.starts_with("gpt-4o") || s.starts_with("chatgpt-4o") => 128000,
                _ => 128000,
            };
            let original_id = m["id"].as_str().unwrap_or("").to_string();
            let thinking = original_id.starts_with("o1") || original_id.starts_with("o3") || original_id.starts_with("o4");
            let vision = original_id.contains("4o") || original_id.starts_with("gpt-5") || original_id.contains("4.1");
            let created_at = m["created"].as_i64()
                .and_then(|s| chrono::DateTime::<chrono::Utc>::from_timestamp(s, 0))
                .map(|dt| dt.to_rfc3339())
                .unwrap_or_default();
            out.push(ModelInfo {
                id: original_id.clone(),
                name: original_id.clone(),
                provider: "openai".to_string(),
                model_id: original_id,
                context_window: context,
                max_output_tokens: 16384,
                capabilities: ModelCapabilities { chat: true, structured_output: true, thinking, vision },
                created_at,
            });
        }
    }
    Ok(out)
}

async fn discover_google_models(api_key: &str) -> Result<Vec<ModelInfo>, String> {
    let client = reqwest::Client::new();
    let mut out = Vec::new();
    let mut page_token: Option<String> = None;
    loop {
        let mut url = format!("https://generativelanguage.googleapis.com/v1beta/models?key={}&pageSize=100", api_key);
        if let Some(ref pt) = page_token {
            url.push_str(&format!("&pageToken={}", pt));
        }
        let resp = client.get(&url).send().await.map_err(|e| e.to_string())?;
        if !resp.status().is_success() {
            return Err(format!("Google models {}: {}", resp.status(), resp.text().await.unwrap_or_default()));
        }
        let data: serde_json::Value = resp.json().await.map_err(|e| e.to_string())?;
        if let Some(arr) = data["models"].as_array() {
            for m in arr {
                let raw_name = m["name"].as_str().unwrap_or("");
                let id = raw_name.strip_prefix("models/").unwrap_or(raw_name).to_string();
                if !id.starts_with("gemini-") { continue; }
                let supports_chat = m["supportedGenerationMethods"].as_array()
                    .map(|a| a.iter().any(|v| v.as_str() == Some("generateContent")))
                    .unwrap_or(false);
                if !supports_chat { continue; }
                out.push(ModelInfo {
                    id: id.clone(),
                    name: m["displayName"].as_str().unwrap_or(&id).to_string(),
                    provider: "google".to_string(),
                    model_id: id.clone(),
                    context_window: m["inputTokenLimit"].as_u64().unwrap_or(32000),
                    max_output_tokens: m["outputTokenLimit"].as_u64().unwrap_or(8192),
                    capabilities: ModelCapabilities {
                        chat: true,
                        structured_output: true,
                        thinking: id.contains("thinking"),
                        vision: true,
                    },
                    created_at: String::new(),
                });
            }
        }
        page_token = data["nextPageToken"].as_str().map(|s| s.to_string());
        if page_token.is_none() { break; }
    }
    Ok(out)
}

