pub async fn discover_models(
    force_refresh: bool,
    store: tauri::State<'_, ApiKeyStore>,
) -> Result<Vec<ModelInfo>, String> {
    let keys: HashMap<String, String> = {
        let g = store.lock().map_err(|e| e.to_string())?;
        g.clone()
    };

    let mut cache = load_model_cache();
    let mut all: Vec<ModelInfo> = Vec::new();
    let mut updated = false;

    for (provider, key_opt) in [
        ("anthropic", keys.get("anthropic")),
        ("openai",    keys.get("openai")),
        ("google",    keys.get("google")),
        ("xai",       keys.get("xai")),
    ] {
        let use_cache = !force_refresh && cache_is_fresh(&cache, provider);
        if use_cache {
            if let Some(entry) = cache.providers.get(provider) {
                all.extend(entry.models.clone());
                continue;
            }
        }
        let api_key = match key_opt {
            Some(k) if !k.is_empty() => k.clone(),
            _ => {
                if let Some(entry) = cache.providers.get(provider) {
                    all.extend(entry.models.clone());
                }
                continue;
            }
        };
        let result = match provider {
            "anthropic" => discover_anthropic_models(&api_key).await,
            "openai"    => discover_openai_models(&api_key).await,
            "google"    => discover_google_models(&api_key).await,
            "xai"       => discover_xai_models(&api_key).await,
            _ => Ok(Vec::new()),
        };
        match result {
            Ok(models) => {
                cache.providers.insert(provider.to_string(), ProviderCache {
                    last_fetched: chrono::Utc::now().to_rfc3339(),
                    models: models.clone(),
                });
                all.extend(models);
                updated = true;
            }
            Err(e) => {
                eprintln!("[ModelDiscovery] {} failed: {}", provider, e);
                if let Some(entry) = cache.providers.get(provider) {
                    all.extend(entry.models.clone());
                }
            }
        }
    }

    if updated {
        save_model_cache(&cache);
    }

    all.sort_by(|a, b| {
        a.provider.cmp(&b.provider).then(b.created_at.cmp(&a.created_at))
    });

    Ok(all)
}
